var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"에퉤퉤…… 모래 폭풍이 강해지고 있어요.","JPN":"ぺっぺっ、砂嵐がさらに強力になってきましたね。","ENG":"Pft. Pft pft... The sandstorm is getting stronger.","TWN":"糟糕……沙塵暴越來越強了。 "},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"역시 저 고래 같은 침식체가 모래 폭풍이 강해진 원인인 건가…….","JPN":"ひょっとして、あのクジラのような侵食体が原因だったり……？","ENG":"So is that whale-like C.O. the reason this sandstorm is getting stronger...?","TWN":"果然是那隻像鯨魚一樣的侵蝕體導致沙塵暴變強的吧……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"저 고래만 토벌한다면 일이 더 수월해진다는 소리로군.","JPN":"あのクジラを倒すことができれば、探索が容易になるだろうな。","ENG":"That means that by killing it, our work here will become easier.","TWN":"意思就是，如果能消滅掉那隻鯨魚，情況會好一點吧。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"무슨 수로요? 몸으로 부딪쳐 봤자 생채기도 안 날 것 같은데요?","JPN":"でもどうやってですか？　こっちの攻撃が通じる相手とはとても思えないんですけど……","ENG":"But how? I don't think we'll be able to even put a scratch in that thing.","TWN":"該怎麼辦？就算是肉搏戰，它應該也不痛不癢吧？"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그러면 여기서 가만히 폭풍에 휩쓸려 죽어야 한다는 건가?","JPN":"では、このまま嵐に飲み込まれて死ねというのか？","ENG":"Then, are you saying you'd rather stay here and let the storm kill you?","TWN":"難道要就這樣靜待沙塵暴將我們吞噬嗎？ "},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"도망쳐야죠. 지금 저렇게 큰 녀석을 어떻게 상대해요?","JPN":"逃げるべきです。あんなデカいやつと戦うなんて、無茶です。","ENG":"We must run away. We're ill-equipped to deal with something that huge.","TWN":"當然跑。問題是現在要怎麼對付那個大塊頭？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그럼 우리가 도망가는 동안 저 녀석은 우리를 가만히 지켜만 보고 있을 거고?","JPN":"私たちが逃げるまで、奴が大人しく待ってくれるとでも思うか？","ENG":"And you think that thing will just stand back and watch as we run away from it?","TWN":"那個大塊頭會坐視我們逃掉嗎？"},"stage":{"bg":"CITY_DESERT","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"누군가는 공격을 막아줘야지.","JPN":"どちらかは奴を止めておかなければならん。","ENG":"Someone has to block its attacks.","TWN":"當然必須要有個人來抵擋攻擊。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그리고 그건 몸이 더 튼튼한 내 역할이다.","JPN":"もちろん、身体が頑丈な私がその役割を担うぞ。","ENG":"And that'll be my job as I'm stronger than you.","TWN":"而這個角色，由我這個身強體壯的來擔任。"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"아유! 목숨이 더 소중하다면서요! 이 거짓말쟁이!","JPN":"もう！　命が優先だって言ったじゃないですか！　嘘つき！","ENG":"Ugh! What about your talk about life being more precious?! Liar!","TWN":"可惡！你不是說過生命更寶貴嗎！你這個騙子！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"걱정하지 마라.","JPN":"大丈夫だ。","ENG":"Don't worry.","TWN":"不用擔心。 "},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"이 무장은 단순한 검이 아니야. 이건…….","JPN":"この装備は単なる剣ではない。これは……","ENG":"This armament is no ordinary sword. This is...","TWN":"這可不是把普通的劍，這是……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"음? 저 녀석, 입에서 뭔가가…….","JPN":"うん？　奴の口から何かが……","ENG":"Hmm? Something coming from its mouth...","TWN":"嗯？那傢伙的嘴巴裡好像……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"엣…… 잠깐…….","JPN":"えっ……ちょっと……","ENG":"Huh...? Hold it...","TWN":"呃……等等……"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"우아악! 멀리서부터 우리를 공격하고 있어요!","JPN":"うわあっ！　遠距離から攻撃してきました！","ENG":"WHOAAA! It's trying to attack us from afar!","TWN":"糟糕！它從遠處攻擊我們！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"입에서 빔을 쏘고 있다고요! 저거!","JPN":"口からビームを出しています！　あいつ！","ENG":"It's shooting a laser beam from its mouth!!","TWN":"嘴巴還會射出光束！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"젠장. 생긴 건 몸으로 밀어붙이게 생겨서는.","JPN":"くっ、いかにも突撃してくるような見た目なんだが。","ENG":"Dammit. This is not expected.","TWN":"該死，還以為只是塊頭大而已！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"이대로 가면 도망이고 뭐고 바싹 익어버릴 거예요! ","JPN":"このままでは逃げる前に、焼け焦げにされてしまいます！ ","ENG":"At this rate, we'll be burnt to a crisp even if we try to run away!","TWN":"再這樣下去，不要說逃跑，我們會直接被烤熟吧！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"원거리에서 공격하면서 우리에게 접근하고 있다!","JPN":"遠距離から攻撃を飛ばしつつ、こちらに向かってきている！","ENG":"It's attacking from a distance while approaching us!","TWN":"那傢伙進行遠距離攻擊的同時也不斷向我們靠近！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"으, 으아아?! 위험해요!","JPN":"う、うわあっ！　危険です！","ENG":"U-uaaah?! Watch out!","TWN":"還不快使用你的武器！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"그 무장인지 뭔지 얼른 써보라고요!","JPN":"その装備はまだ使う気ないんですか！？","ENG":"Use that armament or whatever it's called already!"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"큭! 알고 있어!","JPN":"くっ！　わかっている！","ENG":"Kgh! I'm trying!","TWN":"唔！好！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"무기를 시동하고 힘을 개방하겠다!","JPN":"武器を始動し、力を解放する！","ENG":"I'll activate my weapon and unleash the power!","TWN":"啟動武器，釋放力量！"},"stage":{"bg":"CITY_DESERT","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};